import{_ as t,o as a,c as i,ag as s}from"./chunks/framework.Culc7SYV.js";const u=JSON.parse('{"title":"Language Settings","description":"","frontmatter":{},"headers":[],"relativePath":"Language-Settings.md","filePath":"Language-Settings.md","lastUpdated":1773806339000}'),o={name:"Language-Settings.md"};function n(r,e,l,c,d,g){return a(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="language-settings" tabindex="-1">Language Settings <a class="header-anchor" href="#language-settings" aria-label="Permalink to &quot;Language Settings&quot;">​</a></h1><p>Last modified: 17/03/2026</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>These settings control text-to-speech (TTS) in Settings -&gt; Audio. Flag-based routing uses Circle Flags assets from <a href="https://github.com/HatScripts/circle-flags" target="_blank" rel="noreferrer">HatScripts/circle-flags</a> (MIT).</p><h2 id="audio-settings" tabindex="-1">Audio Settings <a class="header-anchor" href="#audio-settings" aria-label="Permalink to &quot;Audio Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td><strong>TTS Language</strong></td><td>The language/locale for the TTS voice (e.g. <code>en-US</code>, <code>en-GB</code>, <code>fr-FR</code>, <code>de-DE</code>).</td></tr><tr><td><strong>Voice</strong></td><td>The specific voice to use. Available voices depend on your operating system and installed voice packs.</td></tr><tr><td><strong>Speech rate</strong></td><td>How fast the text is read (0.5× to 2.0×). Default is 1.0×.</td></tr><tr><td><strong>Pitch</strong></td><td>Voice pitch adjustment. Default is 1.0.</td></tr></tbody></table><h2 id="script-voices" tabindex="-1">Script Voices <a class="header-anchor" href="#script-voices" aria-label="Permalink to &quot;Script Voices&quot;">​</a></h2><p>LearnKit can map different voices to different writing scripts (for example Latin, Cyrillic, CJK, Arabic).</p><p>How it works:</p><ul><li>LearnKit examines the script (alphabet) of the card text and selects the voice you have assigned to that script.</li><li>LearnKit cannot distinguish languages that share the same script. Example: a Latin-script word shared by English and Italian uses your Latin-script voice, not language-specific detection.</li><li>Your configured default voice is used as a fallback when no script-specific voice is set.</li></ul><p>For flag-based language and accent routing, see <a href="./Flags">Flags</a> and <a href="./Flag-Codes">Flag Codes</a>.</p><h2 id="add-voices" tabindex="-1">Add Voices <a class="header-anchor" href="#add-voices" aria-label="Permalink to &quot;Add Voices&quot;">​</a></h2><h3 id="macos" tabindex="-1">macOS <a class="header-anchor" href="#macos" aria-label="Permalink to &quot;macOS&quot;">​</a></h3><ol><li>Open <strong>System Settings/Preferences → Accessibility → Spoken Content</strong>.</li><li>Click <strong>System Voice → Manage Voices</strong>.</li><li>Download additional voices for your target languages.</li></ol><h3 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to &quot;Windows&quot;">​</a></h3><ol><li>Open <strong>Settings → Time &amp; Language → Speech</strong>.</li><li>Under <strong>Manage voices</strong>, click <strong>Add voices</strong>.</li><li>Choose the languages you need.</li></ol><h3 id="mobile" tabindex="-1">Mobile <a class="header-anchor" href="#mobile" aria-label="Permalink to &quot;Mobile&quot;">​</a></h3><p>Voices are managed in your device system settings (Accessibility or Language/Input).</p><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>For language learning, set the language to your <strong>target</strong> language rather than your native language to practise listening.</li><li>Lower the speech rate when starting out with a new language, then increase it as you improve.</li><li>Try different voices and keep the clearest one for long sessions.</li></ul>',20)])])}const p=t(o,[["render",n]]);export{u as __pageData,p as default};
